/*
 * These are definitions and classes that are shared by the ASR/GL code in the "Jibo" and "Skills-service-manager" packages.
 */

import {types} from '@jibo/jetstream-client';

/**
 * @interface jibo.globalEvents#GlobalEventData
 * @description The payload format for the event {@link jibo.globalEvents#global}.
 * @prop name {string} The name of the global event in question.
 * @prop data {jibo.jetstream.types.ListenResult} The data payload of the global event.
 */
export interface GlobalEventData {
    name: string;
    data: types.ListenResult;
}
/**
 * Enum of global commands.
 * @typedef GlobalCommand
 * @property SLEEP {any} "sleep"
 * @property HELP {any} "help"
 * @property STOP {any} "stop"
 * @property PAUSE {any} "pause"
 * @property VOLUME {any} "volume"
 * @property WHATCANIDO {any} "whatCanIDo"
 * @property HOLDON {any} "holdOn"
 * @property OVERHERE {any} "overHere"
 * @intdocs
 */
export enum GlobalCommand {
    SLEEP = 'SLEEP',
    HELP = 'HELP',
    STOP = 'STOP',
    PAUSE = 'PAUSE',
    VOLUME = 'VOLUME',
    WHATCANIDO = 'WHATCANIDO',
    HOLDON = 'HOLDON',
    OVERHERE = 'OVERHERE',
    TURNAWAY = 'TURNAWAY',
    TURNAROUND = 'TURNAROUND',
}

export const GlobalCommandMap = new Map<string, GlobalCommand>();
GlobalCommandMap.set("sleep", GlobalCommand.SLEEP);
GlobalCommandMap.set("help", GlobalCommand.HELP);
GlobalCommandMap.set("stop", GlobalCommand.STOP);
GlobalCommandMap.set("pause", GlobalCommand.PAUSE);
GlobalCommandMap.set("volume", GlobalCommand.VOLUME);
GlobalCommandMap.set("whatCanIDo", GlobalCommand.WHATCANIDO);
GlobalCommandMap.set("holdOn", GlobalCommand.HOLDON);
GlobalCommandMap.set("overHere", GlobalCommand.OVERHERE);
GlobalCommandMap.set("turnAway", GlobalCommand.TURNAWAY);
GlobalCommandMap.set("turnAround", GlobalCommand.TURNAROUND);

export type Callback = (err?: any, res?: any) => void;
