
/**
 * @description The state of jibo's body.
 * @class BodyState
 * @memberof jibo.system
 */
export class BodyState {
    /**
     * Miscellaneous body state information
     * @name jibo.system.BodyState#miscState
     * @type {jibo.system.MiscState}
     */
    public miscState: MiscState;
    /**
     * Touch pad state information
     * @name jibo.system.BodyState#touchState
     * @type {jibo.system.TouchState}
     */
    public touchState: TouchState;
    /**
     * Power state information
     * @name jibo.system.BodyState#powerState
     * @type {jibo.system.PowerState}
     */
    public powerState: PowerState;
    /**
     * Inertial Measurement Unit (IMU) state information
     * @name jibo.system.BodyState#imuState
     * @type {jibo.system.IMUState}
     */
    public imuState: IMUState;

    constructor() {
        this.miscState = new MiscState();
        this.touchState = new TouchState();
        this.powerState = new PowerState();
        this.imuState = new IMUState();
    }
}

/**
 * @description Miscellaneous body state information.
 * @class MiscState
 * @memberof jibo.system
 */
export class MiscState {
    /**
     * Chronometer timestamp
     * @name jibo.system.MiscState#ts
     * @type {Array<any>}
     */
    public ts:any[];
    /**
     * Main board temperature sensor in degrees Celsius
     * @name jibo.system.MiscState#main_board_temp
     * @type {number}
     */
    public main_board_temp:number;
    /**
     * CPU die temperature in degrees Celsius
     * @name jibo.system.MiscState#cpu_temp
     * @type {number}
     */
    public cpu_temp:number;
    /**
     * Cooling air intake temperature in degrees Celsius
     * @name jibo.system.MiscState#intake_temp
     * @type {number}
     */
    public intake_temp:number;
    /**
     * Cooling air exhaust temperature in degrees Celsius
     * @name jibo.system.MiscState#exhaust_temp
     * @type {number}
     */
    public exhaust_temp:number;
    /**
     * Head motor temperature in degrees Celsius
     * @name jibo.system.MiscState#neck_motor_temp
     * @type {number}
     */
    public neck_motor_temp:number;
    /**
     * Torso motor temperature in degrees Celsius
     * @name jibo.system.MiscState#torso_motor_temp
     * @type {number}
     */
    public torso_motor_temp:number;
    /**
     * Pelvis motor temperature in degrees Celsius
     * @name jibo.system.MiscState#pelvis_motor_temp
     * @type {number}
     */
    public pelvis_motor_temp:number;

    constructor() {
        this.ts = [];
        this.main_board_temp = 0;
        this.cpu_temp = 0;
        this.intake_temp = 0;
        this.exhaust_temp = 0;
        this.neck_motor_temp = 0;
        this.torso_motor_temp = 0;
        this.pelvis_motor_temp = 0;
    }
}

/**
 * @description The state of Jibo's head touchpads.
 * @class TouchState
 * @memberof jibo.system
 */
export class TouchState {
    /**
     * Chronometer timestamp.
     * @name jibo.system.TouchState#ts
     * @type {Array<number>}
     */
    public ts : number[];
    /**
     * `true` if any of the pads have been touched.
     * @name jibo.system.TouchState#touched
     * @type {boolean}
     */
    public touched : boolean;
    /**
     * The array of the 6 pads with `true` for touched and `false` for not touched.
     *
     * See {@tutorial robot-info-tool} for a diagram of Jibo's head touch pads.
     *
     * Three run vertically down the left side of Jibo's head from top to bottom: `pad_state[0, 1, 2]`.
     *
     * Three run vertically down the right of his head: `pad_state[3, 4, 5]`.
     * @name jibo.system.TouchState#pad_state
     * @type {Array<boolean>}
     */
    public pad_state : boolean[];
    /**
     * Array with the indices of the pads that changed in this update. Empty if none.
     * @name jibo.system.TouchState#changed
     * @type {Array<number>}
     */
    public changed: number[];

    constructor() {
        this.ts = [];
        this.touched = false;
        this.pad_state = [false, false, false, false, false, false];
        this.changed = [0,0,0,0,0,0];
    }
}

/**
 * @description Power state information.
 * @class PowerState
 * @memberof jibo.system
 */
export class PowerState {
    /**
     * Chronometer timestamp.
     * @name jibo.system.PowerState#ts
     * @type {Array<number>}
     */
    public ts: any[];
    /**
     * Are we on `'BATTERY'` or `'EXTERNAL'`.
     * @name jibo.system.PowerState#source
     * @type {String}
     */
    public source: string;
    /**
     * The current system voltage estimate.
     * @name jibo.system.PowerState#vsys
     * @type {number}
     */
    public vsys  : number;
    /**
     * Battery object, or undefined if no battery is present or detected.
     * @name jibo.system.PowerState#battery
     * @type {jibo.system.BatteryState}
     */
    public battery : BatteryState;

    constructor() {
        this.ts = [];
        this.source = "";
        this.vsys  = 0;
        this.battery = new BatteryState();
    }
}

/**
 * @description The state of Jibo's battery.
 * @class BatteryState
 * @memberof jibo.system
 */
export class BatteryState {
    /**
     * Battery ID.
     * @name jibo.system.BatteryState#id
     * @type {number}
     */
    public id : number;
    /**
     * Number of battery cycles on this battery.
     * @name jibo.system.BatteryState#cycles
     * @type {number}
     */
    public cycles : number;
    /**
     * Current capacity of this battery in amp hours.
     * @name jibo.system.BatteryState#capacity
     * @type {number}
     */
    public capacity : number;
    /**
     * Maximum capacity of this battery in amp hours.
     * @name jibo.system.BatteryState#max_capacity
     * @type {number}
     */
    public max_capacity : number;
    /**
     * Charge rate of battery. Negative if draining. Positive if charging.
     * @name jibo.system.BatteryState#charge_rate
     * @type {number}
     */
    public charge_rate: number;
    /**
     * Battery temperature in degrees Celsius.
     * @name jibo.system.BatteryState#temp
     * @type {number}
     */
    public temp : number;

    constructor() {
        this.id = 0;
        this.cycles = 0;
        this.capacity = 0;
        this.max_capacity = 0;
        this.charge_rate= 0;
        this.temp = 0;
    }
}

/**
 * @description Inertial Measurement Unit (IMU) State information
 * @class IMUState
 * @memberof jibo.system
 */
export class IMUState {
    /**
     * Chronometer timestamp.
     * @name jibo.system.IMUState#ts
     * @type {Array<number>}
     */
    public ts : number[];
    /**
     * X,Y,Z Accelerations on the robot in m/s^2 in Jibo coordinates.
     * @name jibo.system.IMUState#acc
     * @type {Array<number>}
     */
    public acc : number[];
    /**
     * X,Y,Z Gyroscopic rates on the robot in radians/s in Jibo coordinates.
     * @name jibo.system.IMUState#gyro
     * @type {Array<number>}
     */
    public gyro : number[];
    /**
     * X,Y,Z components of "up" with respect to Jibo coordinates.
     * @name jibo.system.IMUState#up
     * @type {Array<number>}
     */
    public up:  number[];
    /**
     * X,Y,Z Gyroscopic rates on the robot in radians/s in Jibo coordinates.
     * @name jibo.system.IMUState#moving
     * @type {Array<number>}
     */
    public moving: boolean;
    /**
     * X,Y,Z Accelerations on the robot in m/s^2 in undefined coordinates. For debugging.
     * @name jibo.system.IMUState#raw_acc
     * @type {Array<number>}
     */
    public raw_acc: number[];
    /**
     * X,Y,Z Gyroscopic rates on the robot in radians/s in undefined coordinates. For debugging.
     * @name jibo.system.IMUState#raw_gyro
     * @type {Array<number>}
     */
    public raw_gyro: number[];

    constructor() {
        this.ts = [];
        this.acc = [];
        this.gyro = [];
        this.up = [];
        this.moving = false;
        this.raw_acc = [];
        this.raw_gyro = [];
    }
}

/**
 * @description Input Energy as sensed by Jibo.
 * @class InputEnergy
 * @memberof jibo.system
 */
export class InputEnergy {
    /**
     * Chronometer timestamp of this state.
     * @name jibo.system.InputEnergy#ts
     * @type {Array<number>}
     */
    public ts: any[];
    /**
     * Overall dB RMS of input waveform.
     * @name jibo.system.InputEnergy#db_rms
     * @type {number}
     */
    public db_rms: number;
    /**
     *  ~1KHz dB RMS of input waveform.
     * @name jibo.system.InputEnergy#db_high
     * @type {number}
     */
    public db_high: number;
    /**
     *  ~500Hz dB RMS of input waveform.
     * @name jibo.system.InputEnergy#db_mid
     * @type {number}
     */
    public db_mid: number;
    /**
     * ~200Hz dB RMS of input waveform.
     * @name jibo.system.InputEnergy#db_low
     * @type {number}
     */
    public db_low: number;

    constructor() {
        this.ts = [null,null];
        this.db_rms = null;
        this.db_high = null;
        this.db_mid = null;
        this.db_low = null;
    }
}

/**
 * @typedef jibo.system#OneAxisState
 * @description The state of one particular axis.
 * @prop ts {number[]} Chronometer timestamp.
 * @prop pos {number} Absolute (Indexed) position in radians, wraps at +- PI on the axis, undefined until indexed.
 * @prop inc_pos {number} Arbitrary power-up position in ticks; wraps at `2^32`.
 * @prop vel {number} Velocity in radians/second.
 * @prop cur {number} Current in amperes.
 * @prop pwm {number} PWM value in % max PWM.
 * @prop status {jibo.system#StatusFlags} Low level flags for motor and driver status (number).
 * @prop vel_limit {number} Velocity limit in radians/second for trajectory limiting.
 * @prop acc_limit {number} Acceleration limit in radians/second^2 for trajectory limiting.
 * @prop cur_limit {number} Current limit in amperes for torque/power limiting.
 * @prop mode {number} Command mode of the axis in {`none=0`; `limp=1`; `brake=2`; `pwm=3`; `vel=4`; `traj=5`; `trq=6`; `pos_vel=7`}
 * @prop ref {number} Reference value of trajectory generator (depends on command).
 * @prop ref_pos {number} Reference position of trajectory generator (depends on command).
 * @prop ref_acc {number} Reference acceleration of trajectory generator (depends on command).
 * @prop ticks {number} Hardware level tick counter for each axis (milliseconds).
 * @prop integrator {number} Value of the integral term of the PID loop.
 * @prop fault_status {jibo.system#FaultFlags} Low level motor fault flags.
 * @prop index_count {number} Counter of the number of observed index events. Intended for skills to reindex the axis. Wraps after `255`.
 * @prop limiter_mode {number} Motion limiter operation mode (`-1 == DISABLED`, `0 == OK`, `1 == APPROACHING_LIMIT`, `2 == EXCEEDING_LIMIT`).
 */
export interface OneAxisState {
    ts: number[];
    pos: number;
    inc_pos: number;
    vel: number;
    cur: number;
    pwm: number;
    status: StatusFlags;
    vel_limit: number;
    acc_limit: number;
    cur_limit: number;
    mode: number;
    ref: number;
    ref_pos: number;
    ref_acc: number;
    ticks: number;
    integrator: number;
    fault_status: FaultFlags;
    index_count: number;
    limiter_mode: number;
}

/**
 * @typedef jibo.system#AxisState
 * @description All attributes of incoming sectors from LPS Service.
 * @prop {number[]} ts Timestamp in [seconds, microseconds] of event.
 * @prop {jibo.system#OneAxisState} pelvis The Pelvis axis state
 * @prop {jibo.system#OneAxisState} torso The Torso axis state
 * @prop {jibo.system#OneAxisState} neck The Neck axis state
 * @prop {jibo.system#LockoutFlags} lockout Bitmask representing lockout conditions, e.g. system policies that prevent control of the motors
 */
export interface AxisState {
    ts: number[];
    pelvis: OneAxisState;
    torso: OneAxisState;
    neck: OneAxisState;
    lockout: LockoutFlags;
}

/**
 * @typedef jibo.system#StatusFlags
 * @description Enum of axis statuses.
 * @prop INDEXED The axis has been indexed. Position data can be trusted.
 * @prop ENABLED The axis is being commanded.
 * @prop BRAKED The axis is prevented from moving.
 * @prop MOVING The axis is moving.
 * @prop STALLED The axis is unable to drive.
 * @prop TIMEOUT The most recent axis command has expired.
 * @prop FAULT There is an axis fault.
 */
export enum StatusFlags {
	INDEXED,
	ENABLED,
	BRAKED,
	MOVING,
	STALLED,
	TIMEOUT,
	FAULT
}

/**
 * @typedef jibo.system#FaultFlags
 * @description Enum of possible fault statuses.
 * @prop INDEXED The robot is not indexed.
 * @prop POWER Motor is not receiving power.
 * @prop STALL Motion is being prevented by an outside force.
 * @prop ENCODER The encoder value is unreadable.
 * @prop ENCODER_BACKWARDS The encoder count is running backwards.
 * @prop THERMISTOR The thermistor value is out of range.
 */
export enum FaultFlags {
    INDEXED,
    POWER,
	STALL,
	ENCODER,
	ENCODER_BACKWARDS,
	THERMISTOR
}

/**
 * @typedef jibo.system#LockoutFlags
 * @description Enum of possible lockout scenarios.
 * @prop NO_BATTERY Battery is not installed or nonfunctional.
 * @prop NOT_UPRIGHT Orientation is out of bounds.
 * @prop FALLING Acceleration is out of bounds.
 */
export enum LockoutFlags {
    NO_BATTERY,
	NOT_UPRIGHT,
	FALLING
}

/**
 * Enum of the different messages for power sources.
 * @typedef jibo.system#PowerSource
 * @property BATTERY {String} 'BATTERY'
 * @property EXTERNAL {String} 'EXTERNAL'
 */
export enum PowerSource {
    BATTERY = 'BATTERY',
    EXTERNAL = 'EXTERNAL',
}