import * as anim_ns from 'animation-utilities';
import THREE = anim_ns.THREE;
/**
 * Object with x, y, z values. This is not a THREE.Vector3.
 * @prop {number} x X value.
 * @prop {number} y Y value.
 * @prop {number} z Z value.
 * @interface Vector3
 */

/**
 * A geometric feature.
 * @prop {Vector3} position The world coordinates of this feature.
 * @prop {Vector3} direction The direction this features points from its position.
 * @interface KinematicFeature
 */
export interface KinematicFeature {
    position:THREE.Vector3; //world coordinates
    direction:THREE.Vector3;
}

/**
 * Feature set on the expression system
 * @prop {KinematicFeature} base
 * @prop {KinematicFeature} head
 * @prop {KinematicFeature} eye
 * @interface KinematicFeatures
 */
export interface KinematicFeatures {
    base:KinematicFeature;
    head:KinematicFeature;
    eye:KinematicFeature;
}

/**
 * Add/Remove DOFSet-like channels to/from an animation
 * @prop {boolean} BODY
 * @prop {boolean} SCREEN
 * @prop {boolean} AUDIO
 * @interface MuteConfig
 */
export interface MuteConfig {
    BODY: boolean;
    SCREEN: boolean;
    AUDIO: boolean;
}

/**
 * @interface CloneOptions
 * @prop {number} [speed] Animation playback speed.
 * @prop {number} [loops] Number of times to loop animation. `0` loops indefinitely.
 * @prop {DOFOptions} [dofs] Set of DOFs you want animation to play on.
 * @prop {string} [layer] Layer you want to plan anim on. Typically `body`. Can also be `beat`. 
 * @prop {MuteConfig} [mutes] Add and remove groups of DOFs from playback.
 * @prop {Object} [scale] `{ [dofName: string]: number }`
 */
export interface CloneOptions<DOFOptions> {
    speed?:number;
    loops?:number;
    dofs?:DOFOptions;
    layer?: string;
    mutes?: MuteConfig;
    scale?: { [dofName: string]: number };
}

/**
 * @interface AnimationOptions
 * @prop {string} path The absolute path to project directory.
 * @prop {string} src The absolute path to the `.anim` file.
 * @prop {any} [data] The raw anim data. If not provided, the `.anim` file from the path will be loaded instead.
 * @prop {string} [cacheName] A name for a cache. Animation data can be cleared on the server later using {@link jibo.expression#destroyCaches}.
 * @prop {number} [speed] A speed multiplier.
 * @prop {number} [loops] Number of loops to perform on this animation.
 * @prop {DOFSet} [dofs] DOFs to apply this animation to.
 */
export interface AnimationOptions<DOFOptions> extends CloneOptions<DOFOptions> {
    cacheName?:string;
    path:string; // the project root dir.
    src:string; // the DOF file path.
    data?:any;
    //this is a client side filter that filters events
    eventFilter?:(name:string, payload:any) => boolean;
}

/**
 * @interface AcquireOptions
 * @prop {object} position Position of target to acquire
 * @prop {number} position.x `x` position of target in meters.
 * @prop {number} position.y `y` position of target in meters.
 * @prop {number} position.z `z` position of target in meters.
 * @prop {any} [entity] Target entity. May be null if position is provided.
 *                      If position and entity are both provided/valid,
 *                      entity will be used.
 */
export interface AcquireOptions {
    requestor?:string; //default to Behavior
    timeout?:number; //ms
    position:{x:number, y:number, z:number};
    entity?:any;
}

/**
 * @typedef ResultStatus
 * @prop SUCCEEDED
 * @prop TIMEOUT
 * @prop INTERRUPTED
 * @prop CANCELLED
 */
export enum ResultStatus {
    SUCCEEDED = "SUCCEEDED",
    TIMEOUT = "TIMEOUT",
    INTERRUPTED = "INTERRUPTED",
    CANCELLED = "CANCELLED",
}

/**
 * @interface AttentionMode
 * @prop OFF Off.
 * @prop IDLE Idle.
 * @prop RELAXED Relaxed.
 * @prop NAP nap.
 * @prop DISENGAGE Transient disengage.
 * @prop ENGAGED Engaged.
 * @prop SPEAKING Speaking.
 * @prop FIXATED Fixated.
 * @prop ATTRACTABLE Attractable.
 * @prop MENU Menu Mode.
 * @prop COMMAND Direct command mode.
 */
export enum AttentionMode {
    OFF = "OFF",
    IDLE = "IDLE",
    RELAXED = "RELAXED",
    NAP = "NAP",
    DISENGAGE = "DISENGAGE",
    ENGAGED = "ENGAGED",
    SPEAKING = "SPEAKING",
    FIXATED = "FIXATED",
    ATTRACTABLE = "ATTRACTABLE",
    MENU = "MENU",
    COMMAND = "COMMAND"
}

export enum LEDMode {
    OFF = "OFF",
    LISTEN = "LISTEN",
    ERROR = "ERROR",
}

/**
 * @interface CenterOptions
 * @prop {DOFSet} [dofs] The DOFs to act upon.
 * @prop {boolean} [centerGlobally=false] If `true`, center globally. Otherwise do a local center.
 */
export interface CenterOptions<DOFOptions> {
    //defaults to Behavior
    requestor?:string;
    //defaults to DOFSet.ALL
    dofs?:DOFOptions;
    //defualt to false
    centerGlobally?:boolean;
}

/**
 * @interface CleanupOptions
 * @prop {string} [requestor] The requestor (priority level) for the cleanup. Defaults to Behavior.
 * @prop {DOFSet} [dofs] Only clean up the specified DOFs. Defaults to all DOFs.
 * @prop {string[]} [owners] Only clean up the activity of the specified owners. Defaults to all owners.
 * @prop {string} [trustee] Ownership (priority) level for the ongoing cleanup. Defaults to lowest priority.
 */
export interface CleanupOptions<DOFOptions> {
    //defaults to Behavior
    requestor?:string;
    //defaults to DOFSet.ALL
    dofs?:DOFOptions;
    //defaults to all owners
    owners?:string[];
    //defaults to lowest-priority owner
    trustee?:string;
}

/**
 * @typedef IndexRobotResult
 * @prop SUCCEEDED
 * @prop TIMEOUT
 * @prop FAULT
 */
export enum IndexRobotResult {
    SUCCEEDED = "SUCCEEDED",
    TIMEOUT = "TIMEOUT",
    FAULT = "FAULT",
}

/**
 * @interface AwaitFaceOptions
 * @prop {number} timeout - Timeout in seconds; if no face is found in this time, the promise will resolve with status `"TIMEOUT"`.
 *                                  `0` will not wait at all, only currently existing data provided.
 * @prop {number} [maxAngle=0] - Maximum allowed angle (radians) from forward to face.
 *                                      Faces outside this angle are not considered.
 *                                      `0` to search full `maxAngle` range immediately (default).
 * @prop {number} [fullSearchTime=10000] - Time to complete full scan from `0` to `maxAngle`.
 */
export interface AwaitFaceOptions {
    //defualts to 10 seconds
    timeout?:number;
    maxAngle?:number;
    fullSearchTime?:number;
}

/**
 * Results returned when await face is resolved
 * @interface AwaitFaceResult
 * @prop {ResultStatus} status Status of the result.
 * @prop {number} entityId From LPS if it has one.
 * @prop {Object} position `{x, y, z}` position of face.
 * @prop {number} angle Search angle in radians.
 */
export interface AwaitFaceResult {
    status:ResultStatus;
    entityId:number;
    position:{x:number; y:number; z:number};
    angle:number;
}

/**
 * @typedef PlayStatus
 * @prop OK
 * @prop REJECTED
 */
export enum PlayStatus {
    OK = "OK",
    REJECTED = "REJECTED",
}

/**
 * @typedef PlayResult
 * @prop {string} message Any message associated with the result.
 * @prop {PlayStatus} status The status of the animation.
 */
export interface PlayResult {
    message:string;
    status:PlayStatus;
}

export enum ExpressionIds {
    EXPRESSION
}

export interface InstantiateResult<T> {
    instanceId:number;
    state?:T;
}

export interface AnimationInstantiateResult extends InstantiateResult<{
    id:string,
    dofs:string[]
}> {}

export interface InstantiateAndPlayResult {
    instantiateResult:AnimationInstantiateResult;
    playResult:PlayStatus;
}
